        return switch (s) {
            case Circle c -> "Circle r=" + c.r();
            case Rectangle r -> "Rect " + r.w() + "x" + r.h();
        };
    }

    public static void main(String[] args) {
        System.out.println(describe(new Circle(5)));
    }
}

